mapper.select:
SELECT J.JOB_ID , J.JOB_NAME , J.DAEMON_ID , F.DAEMON_CD , J.DELIMITER , F.DAEMON_NM , J.BASE_DATE , F.DAEMON_RESTART_YN , J.USE_YN , (SELECT SERVER_NM FROM mhdb.TB_SERVER G WHERE J.SRC_SERVER_ID = G.SERVER_ID) AS SRC_SERVER_NM , J.SRC_SERVER_ID , J.SRC_TABLE_ID , (SELECT TABLE_CD FROM mhdb.TB_TABLE_INFO T WHERE J.SRC_TABLE_ID = T.TABLE_ID) AS SRC_TABLE_CD , (SELECT TABLE_NM FROM mhdb.TB_TABLE_INFO T WHERE J.SRC_TABLE_ID = T.TABLE_ID) AS SRC_TABLE_NM , J.DES_FILE_PATH , J.DES_FLAG_PATH , J.DES_TABLE_ID , J.DES_SERVER_ID , (SELECT SERVER_NM FROM mhdb.TB_SERVER G WHERE J.DES_SERVER_ID = G.SERVER_ID) AS DES_SERVER_NM , (SELECT TABLE_CD FROM mhdb.TB_TABLE_INFO T WHERE J.DES_TABLE_ID = T.TABLE_ID) AS DES_TABLE_CD , (SELECT TABLE_NM FROM mhdb.TB_TABLE_INFO T WHERE J.DES_TABLE_ID = T.TABLE_ID) AS DES_TABLE_NM , J.JOB_SCHEDULE , J.JOB_TYPE FROM mhdb.TB_DB_JOB_MST J JOIN mhdb.TB_DAEMON F ON J.DAEMON_ID = F.DAEMON_ID WHERE 1 = 1 AND F.DAEMON_ID = #{daemonId}
AND J.USE_YN = #{useYn}
AND J.JOB_ID = #{jobId}::integer
AND J.JOB_NAME LIKE CONCAT('%', #{jobNm}, '%')
ORDER BY J.JOB_NAME

mapper.update:
UPDATE mhdb.TB_LOAD_JOB_MST
   SET SERVER_ID = #{server_id}::integer
	 , JOB_NM = #{job_nm}
	 , JOB_CD = #{job_cd}
	 , TABLE_ID = #{table_id}::integer
	 , SOURCE_PATH = #{source_path}
	 , SOURCE_FILE = #{source_file}
	 , INFO_PATH = #{info_path}
	 , INFO_FILE = #{info_file}
	 , JOB_TM = #{job_tm}
	 , SCHEDULE_YN = #{schedule_yn}
	 , SCHEDULE_VALUE = #{schedule_value}
	 , ERROR_PATH = #{error_path}
	 , SOURCE_DEL_YN = #{source_del_yn}
	 , LAST_COL_YN = #{last_col_yn}
	 , USE_YN = #{use_yn}
 WHERE JOB_ID = #{job_id}::integer

UPDATE mhdb.TB_CONV_JOB_MST
   SET OUTPUT1_SERVERID = #{output1_server_id}::integer
	 , OUTPUT2_SERVERID = #{output2_server_id}::integer
	 , JOB_NM = #{job_nm}
	 , JOB_CD = #{job_cd}
	 , OUTPUT1_TABLEID = #{table_id}::integer
	 , OUTPUT2_TABLEID = #{table_id2}::integer
	 , SOURCE_PATH = #{source_path}
	 , SOURCE_FILE = #{source_file}
	 , OUTPUT1_INFO_PATH = #{info_path}
	 , OUTPUT1_INFO_FILE = #{info_file}
	 , OUTPUT2_INFO_PATH = #{info_path2}
	 , OUTPUT2_INFO_FILE = #{info_file2}
	 , JOB_TM = #{job_tm}
	 , SCHEDULE_YN = #{schedule_yn}
	 , SCHEDULE_VALUE = #{schedule_value}
	 , SOURCE_DEL_YN = #{source_del_yn}
	 , LAST_COL_YN = #{last_col_yn}
	 , USE_YN = #{use_yn}
 WHERE JOB_ID = #{job_id}

UPDATE mhdb.TB_DB_JOB_MST
   SET SRC_SERVER_ID = #{src_server_id}::integer
	 , DES_SERVER_ID = #{des_server_id}::integer
	 , JOB_NAME = #{job_nm}
	 , SRC_TABLE_ID = #{src_table_id}::integer
	 , DES_TABLE_ID = #{des_table_id}::integer
	 , DELIMITER = #{delimiter}
	 , DES_FILE_PATH = #{des_file_path}
	 , DES_FLAG_PATH = #{des_flag_path}
	 , BASE_DATE = #{base_date}
	 , JOB_SCHEDULE = #{job_schedule}
	 , JOB_TYPE = #{job_type}
	 , USE_YN = #{use_yn}
 WHERE JOB_ID = #{job_id}
